class Solution {
public:
    int kIncreasing(vector<int>& arr, int k) {
        int n = arr.size();
        int operations = 0;
        for (int i = 0; i < k; ++i) {
            vector<int> subsequence;
            for (int j = i; j < n; j += k) {
                subsequence.push_back(arr[j]);
            }
            operations += getOperations(subsequence);
        }
        return operations;
    }

    int getOperations(vector<int>& subsequence) {
        int n = subsequence.size();
        vector<int> dp(n, 1);
        int maxLength = 1;
        for (int i = 1; i < n; ++i) {
            for (int j = 0; j < i; ++j) {
                if (subsequence[j] <= subsequence[i]) {
                    dp[i] = max(dp[i], dp[j] + 1);
                }
            }
            maxLength = max(maxLength, dp[i]);
        }
        return n - maxLength;
    }
};
